// Fetch ALL transactions for the last N minutes by paging until we have
// everything the portal reports in 'Total'. Window computed in the portal's
// timezone (US Eastern). Uses this.helpers.httpRequest to avoid the HTTP
// Request node's TLSSocket/gzip bug in n8n 2.x.

const input = $input.first().json;

let session;
try {
  session = typeof input.sessionJson === 'string' ? JSON.parse(input.sessionJson) : input.sessionJson;
} catch (e) {
  throw new Error('sessionJson is not valid JSON. Paste the full contents of session.json.');
}
if (!session.cookies || !session.token) {
  throw new Error('session.json missing cookies or token. Re-run login.');
}
const cookie = session.cookies.map(c => `${c.name}=${c.value}`).join('; ');
const token = session.token;
const base = (session.portalUrl || 'https://integration.commonwellalliance.lkopera.com/').replace(/\/$/, '');
const url = base + '/TransactionLogs/BindTransactionLogs';

const windowMinutes = input.windowMinutes || 30;
const pageSize = input.pageSize || 100;
const status = input.status || 'All';
const portalTz = input.portalTimeZone || 'America/New_York';

function fmtInTz(d, tz) {
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: tz,
    year: 'numeric', month: 'numeric', day: 'numeric',
    hour: 'numeric', minute: '2-digit', second: '2-digit',
    hour12: true
  }).formatToParts(d);
  const p = {};
  for (const part of parts) p[part.type] = part.value;
  return `${p.month}/${p.day}/${p.year} ${p.hour}:${p.minute}:${p.second} ${p.dayPeriod}`;
}
const now = new Date();
const from = new Date(now.getTime() - windowMinutes * 60000);
const fromDate = fmtInTz(from, portalTz);
const toDate = fmtInTz(now, portalTz);

const enc = encodeURIComponent;
function buildBody(page) {
  const fields = {
    sort: 'transactionId-asc', page: String(page), pageSize: String(pageSize),
    group: '', filter: '', Status: status, FromDate: fromDate, ToDate: toDate,
    organizationId: '', MemberId: '', TransactionType: '', TransactionId: '',
    before: '', after: '', __RequestVerificationToken: token
  };
  return Object.keys(fields).map(k => `${enc(k)}=${enc(fields[k])}`).join('&');
}

async function fetchPage(page) {
  const respBody = await this.helpers.httpRequest({
    method: 'POST', url,
    headers: {
      'Cookie': cookie,
      'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8',
      'X-Requested-With': 'XMLHttpRequest', 'Accept': '*/*',
      'Origin': base, 'Referer': base + '/TransactionLogs/index'
    },
    body: buildBody(page), json: false
  });
  let resp = respBody;
  if (typeof resp === 'string') {
    const t = resp.trim();
    if (t.startsWith('<')) throw new Error('Got HTML instead of JSON — session expired. Re-run login.');
    resp = JSON.parse(t);
  }
  return resp;
}

let allRows = [];
let page = 1;
const first = await fetchPage.call(this, page);
const total = (first && (first.Total || first.total)) || 0;
let rows = (first && (first.Data || first.data || first.rows)) || [];
allRows = allRows.concat(rows);

const maxPages = 200;
while (allRows.length < total && page < maxPages) {
  page++;
  const next = await fetchPage.call(this, page);
  const nextRows = (next && (next.Data || next.data || next.rows)) || [];
  if (nextRows.length === 0) break;
  allRows = allRows.concat(nextRows);
}

return [{ json: { rows: allRows, count: allRows.length, total, fromDate, toDate,
  webhookUrl: input.teamsWebhookUrl, portalTz } }];

// Inspect every transaction for client errors (any status that isn't
// 'Successful') and build a report. Always passes one item downstream with
// hasErrors + a ready-to-send Teams MessageCard.

const data = $input.first().json;
const rows = data.rows || [];

// a transaction is an error if status isn't 'Successful' (case-insensitive)
const isError = (r) => {
  const s = (r.status || '').toString().toLowerCase();
  return s !== 'successful' && s !== 'success' && s !== '';
};

const errors = rows.filter(isError);
const hasErrors = errors.length > 0;

// group error counts by transactionType for a compact summary
const byType = {};
for (const e of errors) {
  const t = e.transactionType || 'Unknown';
  byType[t] = (byType[t] || 0) + 1;
}
const typeSummary = Object.keys(byType).map(t => `${t}: ${byType[t]}`).join(', ') || 'none';

// build a list of up to 10 failed transaction ids for the card
const sampleLines = errors.slice(0, 10).map(e =>
  `- ${e.transactionType || '?'} | ${e.status} | ${e.transactionId} | ${e.Timestamp || ''}`
).join('\n');
const more = errors.length > 10 ? `\n…and ${errors.length - 10} more` : '';

// Teams MessageCard (legacy Incoming Webhook format)
const card = {
  '@type': 'MessageCard',
  '@context': 'http://schema.org/extensions',
  themeColor: hasErrors ? 'D70000' : '2EB67D',
  summary: hasErrors ? `CommonWell: ${errors.length} failed transactions` : 'CommonWell: all clear',
  title: hasErrors
    ? `⚠️ CommonWell: ${errors.length} failed transaction(s)`
    : '✅ CommonWell: no errors',
  sections: [{
    facts: [
      { name: 'Window', value: `${data.fromDate} – ${data.toDate} (${data.portalTz})` },
      { name: 'Total in window', value: String(data.count) },
      { name: 'Failed', value: String(errors.length) },
      { name: 'By type', value: typeSummary }
    ],
    text: hasErrors ? ('```\n' + sampleLines + more + '\n```') : ''
  }]
};

return [{
  json: {
    hasErrors,
    errorCount: errors.length,
    totalCount: data.count,
    window: `${data.fromDate} – ${data.toDate}`,
    errors,
    webhookUrl: data.webhookUrl,
    teamsCard: card
  }
}];
